const title = $.input.issueTitle || '';
const desc = $.input.issueDescription || '';
const history = $.input.issueHistory || '';
const customer = $.input.customerName || 'Customer';

let prompt = 'You are a customer support AI specialist. Analyze the following support issue and perform classification, sentiment analysis, and solution lookup.\n\n';
prompt += 'ISSUE TITLE: ' + title + '\n';
prompt += 'DESCRIPTION: ' + desc + '\n';
if (history) prompt += 'CONVERSATION HISTORY:\n' + history + '\n';
prompt += 'CUSTOMER: ' + customer + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '1. Classify the issue into a category (billing, technical, account, feature_request, bug, general)\n';
prompt += '2. Analyze customer sentiment (positive, neutral, frustrated, angry)\n';
prompt += '3. Assess priority (critical, high, medium, low)\n';
prompt += '4. Check if the issue is likely resolved or needs follow-up\n';
prompt += '5. Suggest a solution based on common support knowledge\n';
prompt += '6. Draft a professional reply to the customer\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "category": "billing|technical|account|feature_request|bug|general",\n';
prompt += '  "sentiment": "positive|neutral|frustrated|angry",\n';
prompt += '  "priority": "critical|high|medium|low",\n';
prompt += '  "isResolved": false,\n';
prompt += '  "suggestedSolution": "detailed solution",\n';
prompt += '  "draftReply": "professional reply to customer",\n';
prompt += '  "escalationNeeded": false,\n';
prompt += '  "escalationReason": "",\n';
prompt += '  "similarIssueKeywords": ["keyword1", "keyword2"],\n';
prompt += '  "summary": "1-2 sentence issue summary"\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiClassification.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { category: 'general', sentiment: 'neutral', priority: 'medium', isResolved: false, suggestedSolution: raw.slice(0, 500), draftReply: '', escalationNeeded: false, escalationReason: '', similarIssueKeywords: [], summary: raw.slice(0, 200) }; }

const ai = $.steps.parseAI.output;
const blocks = [];

let priorityEmoji = '';
if (ai.priority === 'critical') priorityEmoji = ':red_circle:';
else if (ai.priority === 'high') priorityEmoji = ':large_orange_circle:';
else if (ai.priority === 'medium') priorityEmoji = ':large_yellow_circle:';
else priorityEmoji = ':white_circle:';

blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Support Issue Analysis', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + ($.input.issueTitle || 'Issue') + '*\n' + (ai.summary || '').slice(0, 500) } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Category:*\n' + (ai.category || 'N/A') },
  { type: 'mrkdwn', text: '*Priority:* ' + priorityEmoji + '\n' + (ai.priority || 'N/A') }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Sentiment:*\n' + (ai.sentiment || 'N/A') },
  { type: 'mrkdwn', text: '*Customer:*\n' + ($.input.customerName || 'Unknown') }
] });
blocks.push({ type: 'divider' });

if (ai.suggestedSolution) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Suggested Solution:*\n' + ai.suggestedSolution.slice(0, 1500) } });
}
if (ai.draftReply) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Draft Reply:*\n' + ai.draftReply.slice(0, 1500) } });
}

if (ai.escalationNeeded) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':warning: *Escalation Needed:* ' + (ai.escalationReason || 'See details above') } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Logged to Notion | Powered by Claude AI' }] });
const fallbackText = 'Support Issue [' + (ai.priority || '?').toUpperCase() + ']: ' + ($.input.issueTitle || 'Issue') + ' - ' + (ai.category || '');
return { blocks, fallbackText, escalationNeeded: ai.escalationNeeded };
